const store = $.stanz({ count: 0 });

// 在组件中
export default {
  data: {
    store: {}
  },
  proto:{
    increment() {
        store.count++; // 所有引用了 store.count 的组件都会自动更新
    }
  },
  attached() {
    // 直接引用状态对象的属性
    this.store = store;
  },
  detached(){
    this.store = {}; // 组件销毁时，清空挂载的状态数据
  }
};
```

